public class CampaignScheduler {
    static class Campaign {
        int cost;
        int expectedReturn;

        Campaign(int cost, int expectedReturn) {
            this.cost = cost;
            this.expectedReturn = expectedReturn;
        }
    }

    public static int maximizeReturn(Campaign[] campaigns, int budget) {
        int n = campaigns.length;
        int[][] dp = new int[n + 1][budget + 1];

        for (int i = 1; i <= n; i++) {
            int cost = campaigns[i - 1].cost;
            int expectedReturn = campaigns[i - 1].expectedReturn;

            for (int j = 0; j <= budget; j++) {
                if (j >= cost) {
                    dp[i][j] = Math.max(dp[i - 1][j], dp[i - 1][j - cost] + expectedReturn);
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }

        return dp[n][budget];
    }

    public static void main(String[] args) {
        Campaign[] campaigns = {
            new Campaign(20, 50),
            new Campaign(30, 60),
            new Campaign(50, 100)
        };
        int budget = 50;
        System.out.println("Maximum Return: " + maximizeReturn(campaigns, budget));
    }
}

def knapsack(max_weight, weights, values, n):
    # Creating a 2D array to store results of subproblems
    dp = [[0 for _ in range(max_weight + 1)] for _ in range(n + 1)]

    # Build table dp[][] in bottom-up manner
    for i in range(n + 1):
        for w in range(max_weight + 1):
            if i == 0 or w == 0:
                dp[i][w] = 0
            elif weights[i - 1] <= w:
                dp[i][w] = max(values[i - 1] + dp[i - 1][w - weights[i - 1]], dp[i - 1][w])
            else:
                dp[i][w] = dp[i - 1][w]

    return dp[n][max_weight]

