    std::cout << "Maximum Profit: " << maxProfit(stockPrices) << std::endl;
    return 0;
}

def max_revenue(products, discount_limit):
    n = len(products)
    dp = [[0 for _ in range(discount_limit + 1)] for _ in range(n + 1)]

    for i in range(1, n + 1):
        revenue, discount = products[i - 1]
        for j in range(discount_limit + 1):
            if discount <= j:
                dp[i][j] = max(dp[i - 1][j], revenue + dp[i - 1][j - discount])
            else:
                dp[i][j] = dp[i - 1][j]

    return dp[n][discount_limit]

