def warehouse_inventory(n_weeks, demands, prices, storage_costs, max_capacity):
    dp = [[float('inf')] * (max_capacity + 1) for _ in range(n_weeks + 1)]
    dp[0][0] = 0

    for week in range(1, n_weeks + 1):
        for inventory in range(max_capacity + 1):
            # Option 1: Do not order this week
            if inventory >= demands[week - 1]:
                dp[week][inventory - demands[week - 1]] = min(
                    dp[week][inventory - demands[week - 1]],
                    dp[week - 1][inventory] + inventory * storage_costs[week - 1]
                )

            # Option 2: Order in advance
            for order in range(max_capacity - inventory + 1):
                if inventory + order >= demands[week - 1]:
                    dp[week][inventory + order - demands[week - 1]] = min(
                        dp[week][inventory + order - demands[week - 1]],
                        dp[week - 1][inventory] + order * prices[week - 1] + inventory * storage_costs[week - 1]
                    )

    return min(dp[n_weeks])

