// Function to calculate the minimum route cost using memoization
int minRouteCost(int currentLocation, int visitedMask, int truckLoad, const vector<vector<int>>& distances, const vector<int>& garbageLocations, int capacity, unordered_map<string, int>& memo) {
    if (visitedMask == (1 << garbageLocations.size()) - 1) {
        return distances[currentLocation][0]; // Return to starting point
    }

    string key = to_string(currentLocation) + "," + to_string(visitedMask) + "," + to_string(truckLoad);
    if (memo.find(key) != memo.end()) {
        return memo[key];
    }

    int result = INT_MAX;
    for (int i = 0; i < garbageLocations.size(); ++i) {
        if (!(visitedMask & (1 << i)) && truckLoad + garbageLocations[i] <= capacity) { // Not visited and within capacity
            int newCost = distances[currentLocation][i + 1] + minRouteCost(i + 1, visitedMask | (1 << i), truckLoad + garbageLocations[i], distances, garbageLocations, capacity, memo);
            result = min(result, newCost);
        }
    }

    memo[key] = result;
    return result;
}

int main() {
    vector<vector<int>> distances = {
        {0, 10, 15, 20},
        {10, 0, 35, 25},
        {15, 35, 0, 30},
        {20, 25, 30, 0}
    };

    vector<int> garbageLocations = {5, 10, 5};  // Garbages at each location
    int capacity = 15;  // Truck capacity

    unordered_map<string, int> memo;
    int minCost = minRouteCost(0, 0, 0, distances, garbageLocations, capacity, memo);

    cout << "Minimum cost to collect all garbage: " << minCost << endl;

    return 0;
}

import java.util.ArrayList;
import java.util.List;

public class TextJustification {
    private final int maxWidth;
    private final String hyphen = "-";
    private List<String> words;
    private List<Integer> memo;
    private List<Integer> breakPoints;

    public TextJustification(List<String> words, int maxWidth) {
        this.words = words;
        this.maxWidth = maxWidth;
        this.memo = new ArrayList<>(words.size());
        this.breakPoints = new ArrayList<>(words.size());
        for (int i = 0; i < words.size(); i++) {
            memo.add(-1);
            breakPoints.add(-1);
        }
    }

    public List<String> justify() {
        int cost = calculateCost(0);
        return constructSolution(breakPoints, words.size());
    }

    private int calculateCost(int index) {
        if (index == words.size()) return 0;
        if (memo.get(index) != -1) return memo.get(index);

        int minCost = Integer.MAX_VALUE;
        int currentLen = 0;
        for (int i = index; i < words.size(); i++) {
            String word = words.get(i);
            int remainingLen = maxWidth - currentLen;
            if (!canFit(remainingLen, word)) break;

            currentLen += (currentLen != 0 ? 1 : 0) + word.length();
            if (i < words.size() - 1 && currentLen + words.get(i+1).length() > maxWidth) {
                String hyphenated = word.length() > 1 ? word.substring(0, word.length()-1) + hyphen : word;
                if (currentLen - word.length() + hyphenated.length() <= maxWidth) {
                    currentLen = currentLen - word.length() + hyphenated.length();
                }
            }

            int cost = calculateCost(i + 1);
            int totalCost = cost + justifyCost(currentLen);
            if (totalCost < minCost) {
                minCost = totalCost;
                breakPoints.set(index, i + 1);
            }
        }
        memo.set(index, minCost);
        return minCost;
    }

    private List<String> constructSolution(List<Integer> breakPoints, int size) {
        List<String> result = new ArrayList<>();
        int start = 0;
        while (start < size) {
            int end = breakPoints.get(start);
            StringBuilder line = new StringBuilder();
            for (int i = start; i < end; i++) {
                line.append(words.get(i));
                if (i < end - 1) line.append(" ");
            }
            result.add(line.toString());
            start = end;
        }
        return result;
    }

    private boolean canFit(int remainingLen, String word) {
        return word.length() <= remainingLen || (word.length() > remainingLen && word.length() > 1 && word.substring(0, word.length() - 1).length() + hyphen.length() <= remainingLen);
    }

    private int justifyCost(int lineLen) {
        return (int) Math.pow(maxWidth - lineLen, 2);
    }

    public static void main(String[] args) {
        List<String> paragraph = List.of("This", "is", "an", "example", "of", "text", "justification");
        int maxWidth = 16;

        TextJustification tj = new TextJustification(paragraph, maxWidth);
        List<String> justifiedText = tj.justify();

        for (String line : justifiedText) {
            System.out.println(line);
        }
    }
}

