// Function to find the maximum sum subarray using Kadane's algorithm
int findMaxSubarraySum(const std::vector<int>& readings) {
    int maxSum = INT_MIN;
    int currentSum = 0;
    for (int reading : readings) {
        currentSum = std::max(reading, currentSum + reading);
        maxSum = std::max(maxSum, currentSum);
    }
    return maxSum;
}

int main() {
    // Example usage:
    std::vector<int> sensorReadings = {1, -2, 3, 4, -1, 2, 1, -5, 4};
    int maxIntensity = findMaxSubarraySum(sensorReadings);
    std::cout << "Maximum cumulative intensity: " << maxIntensity << std::endl;
    return 0;
}

