public class EvacuationRoutePlannerDP {
    private static final int INF = Integer.MAX_VALUE;

    public static class Graph {
        private final int V;
        private final List<List<Edge>> adj;

        public Graph(int V) {
            this.V = V;
            adj = new ArrayList<>(V);
            for (int i = 0; i < V; i++) {
                adj.add(new ArrayList<>());
            }
        }

        public void addEdge(int u, int v, int weight) {
            adj.get(u).add(new Edge(v, weight));
        }

        public List<Edge> getAdj(int u) {
            return adj.get(u);
        }
    }

    public static class Edge {
        private final int v;
        private int weight;

        public Edge(int v, int weight) {
            this.v = v;
            this.weight = weight;
        }

        public int getV() {
            return v;
        }

        public int getWeight() {
            return weight;
        }

        public void setWeight(int weight) {
            this.weight = weight;
        }
    }

    public static int[][] shortestPathDP(Graph graph, int source) {
        int V = graph.adj.size();
        int[][] dp = new int[V][V];
        int[][] next = new int[V][V];

        for (int i = 0; i < V; i++) {
            Arrays.fill(dp[i], INF);
            dp[i][i] = 0;
            for (Edge edge : graph.getAdj(i)) {
                dp[i][edge.getV()] = edge.getWeight();
                next[i][edge.getV()] = edge.getV();
            }
        }

        for (int k = 0; k < V; k++) {
            for (int i = 0; i < V; i++) {
                for (int j = 0; j < V; j++) {
                    if (dp[i][k] != INF && dp[k][j] != INF && dp[i][j] > dp[i][k] + dp[k][j]) {
                        dp[i][j] = dp[i][k] + dp[k][j];
                        next[i][j] = next[i][k];
                    }
                }
            }
        }

        return next;
    }

    public static List<Integer> reconstructPath(int[][] next, int start, int end) {
        if (next[start][end] == 0) return null;
        List<Integer> path = new ArrayList<>();
        int at = start;
        while (at != end) {
            path.add(at);
            at = next[at][end];
        }
        path.add(end);
        return path;
    }

