import java.util.*;

public class SuffixArraySearch {
    private String[] titles;
    private String[] suffixArray;
    private int[] indexes;

    public SuffixArraySearch(String[] titles) {
        this.titles = titles;
        buildSuffixArray();
    }

    private void buildSuffixArray() {
        List<String> suffixList = new ArrayList<>();
        indexes = new int[titles.length];
        for (int i = 0; i < titles.length; i++) {
            String title = titles[i];
            for (int j = 0; j < title.length(); j++) {
                suffixList.add(title.substring(j));
                indexes[suffixList.size() - 1] = i;
            }
        }
        suffixArray = suffixList.toArray(new String[0]);
        Arrays.sort(suffixArray, Comparator.naturalOrder());
    }

    public List<String> search(String query) {
        List<String> results = new ArrayList<>();
        int idx = binarySearch(query);

        while (idx < suffixArray.length && suffixArray[idx].startsWith(query)) {
            results.add(titles[indexes[idx]]);
            idx++;
        }

        results.sort((a, b) -> {
            int relevanceComparison = Integer.compare(countOccurrences(a, query), countOccurrences(b, query));
            return relevanceComparison != 0 ? -relevanceComparison : a.compareTo(b);
        });

        return results;
    }

    private int binarySearch(String query) {
        int low = 0, high = suffixArray.length;
        while (low < high) {
            int mid = (low + high) / 2;
            if (suffixArray[mid].compareTo(query) < 0) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        return low;
    }

    private int countOccurrences(String title, String query) {
        int count = 0;
        int idx = title.indexOf(query);
        while (idx != -1) {
            count++;
            idx = title.indexOf(query, idx + 1);
        }
        return count;
    }

    public static void main(String[] args) {
        String[] documentTitles = {"search", "suffix array", "indexing relevance", "query optimization", "efficient retrieval"};
        SuffixArraySearch searchEngine = new SuffixArraySearch(documentTitles);

        String[] queries = {"search", "suffix", "query"};
        for (String query : queries) {
            System.out.println("Results for query '" + query + "': " + searchEngine.search(query));
        }
    }
}

import pickle

class BTreeNode:
    def __init__(self, t, leaf=False):
        self.keys = []
        self.children = []
        self.leaf = leaf
        self.degree = t

class BTree:
    def __init__(self, t):
        self.root = BTreeNode(t, True)
        self.degree = t

    def insert(self, key, value):
        root = self.root
        if len(root.keys) == (2 * self.degree) - 1:
            temp = BTreeNode(self.degree)
            self.root = temp
            temp.children.insert(0, root)
            self.split_child(temp, 0)
            self._insert_non_full(temp, key, value)
        else:
            self._insert_non_full(root, key, value)

    def _insert_non_full(self, node, key, value):
        i = len(node.keys) - 1
        if node.leaf:
            node.keys.append(None)
            node.children.append(None)
            while i >= 0 and key < node.keys[i][0]:
                node.keys[i + 1] = node.keys[i]
                i -= 1
            node.keys[i + 1] = (key, value)
        else:
            while i >= 0 and key < node.keys[i][0]:
                i -= 1
            i += 1
            if len(node.children[i].keys) == (2 * self.degree) - 1:
                self.split_child(node, i)
                if key > node.keys[i][0]:
                    i += 1
            self._insert_non_full(node.children[i], key, value)

    def split_child(self, parent, i):
        t = self.degree
        child = parent.children[i]
        new_child = BTreeNode(t, child.leaf)
        parent.children.insert(i + 1, new_child)
        parent.keys.insert(i, child.keys[t - 1])
        new_child.keys = child.keys[t:(2 * t) - 1]
        if not child.leaf:
            new_child.children = child.children[t:(2 * t)]
        child.keys = child.keys[0:t - 1]
        child.children = child.children[0:t]

    def search(self, key):
        return self._search(self.root, key)

    def _search(self, node, key):
        i = 0
        while i < len(node.keys) and key > node.keys[i][0]:
            i += 1
        if i < len(node.keys) and key == node.keys[i][0]:
            return node.keys[i][1]
        elif node.leaf:
            return None
        else:
            return self._search(node.children[i], key)

    def delete(self, key):
        pass  # Delete operation not implemented for brevity

    def persist(self, filename):
        with open(filename, 'wb') as f:
            pickle.dump(self, f)

    @staticmethod
    def load(filename):
        with open(filename, 'rb') as f:
            return pickle.load(f)

class FileSystemIndex:
    def __init__(self, degree=3):
        self.btree = BTree(degree)

    def add_file(self, filename, creation_date, size):
        self.btree.insert(filename, {'creation_date': creation_date, 'size': size})

    def update_file(self, filename, creation_date=None, size=None):
        metadata = self.btree.search(filename)
        if metadata:
            if creation_date:
                metadata['creation_date'] = creation_date
            if size:
                metadata['size'] = size
            self.btree.insert(filename, metadata)

    def remove_file(self, filename):
        self.btree.delete(filename)

    def lookup_file(self, filename):
        return self.btree.search(filename)

    def save_index(self, filepath):
        self.btree.persist(filepath)

    @staticmethod
    def load_index(filepath):
        btree = BTree.load(filepath)
        index = FileSystemIndex(btree.degree)
        index.btree = btree
        return index

#include <iostream>
#include <vector>
#include <stdexcept>

struct Task {
    int priority;
    int executionTime;

    Task(int p, int e) : priority(p), executionTime(e) {}

    bool operator<(const Task& other) const {
        return priority < other.priority;
    }
};

class TaskScheduler {
    std::vector<Task> taskHeap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (taskHeap[index] < taskHeap[parent]) {
                break;
            }
            std::swap(taskHeap[index], taskHeap[parent]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int size = taskHeap.size();
        while (index < size) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int largest = index;

            if (left < size && taskHeap[left] < taskHeap[largest]) {
                largest = left;
            }
            if (right < size && taskHeap[right] < taskHeap[largest]) {
                largest = right;
            }
            if (largest == index) {
                break;
            }
            std::swap(taskHeap[index], taskHeap[largest]);
            index = largest;
        }
    }

public:
    void addTask(int priority, int executionTime) {
        taskHeap.emplace_back(priority, executionTime);
        heapifyUp(taskHeap.size() - 1);
    }

    Task fetchNextTask() {
        if (taskHeap.empty()) {
            throw std::runtime_error("No tasks available");
        }
        return taskHeap.front();
    }

    void removeCompletedTask() {
        if (taskHeap.empty()) {
            throw std::runtime_error("No tasks to remove");
        }
        std::swap(taskHeap[0], taskHeap.back());
        taskHeap.pop_back();
        if (!taskHeap.empty()) {
            heapifyDown(0);
        }
    }

    bool hasTasks() const {
        return !taskHeap.empty();
    }
};

int main() {
    TaskScheduler scheduler;
    scheduler.addTask(5, 10);
    scheduler.addTask(10, 5);
    scheduler.addTask(7, 15);

    while (scheduler.hasTasks()) {
        Task task = scheduler.fetchNextTask();
        std::cout << "Executing task with priority: " << task.priority << " and execution time: " << task.executionTime << "\n";
        scheduler.removeCompletedTask();
    }

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_NODES 100

typedef struct {
    int adj[MAX_NODES][MAX_NODES];
    int numNodes;
} Graph;

void readGraphFromFile(Graph* graph, const char* filename) {
    FILE* file = fopen(filename, "r");
    if (!file) {
        perror("Unable to open file");
        exit(EXIT_FAILURE);
    }

    int u, v;
    while (fscanf(file, "%d %d", &u, &v) != EOF) {
        graph->adj[u][v] = 1;
        graph->adj[v][u] = 1;
    }

    fclose(file);
}

int bfs(Graph* graph, int start, int target) {
    int visited[MAX_NODES] = {0};
    int queue[MAX_NODES], front = 0, rear = 0;

    visited[start] = 1;
    queue[rear++] = start;

    while (front < rear) {
        int current = queue[front++];
        if (current == target) {
            return 1;
        }
        for (int i = 0; i < graph->numNodes; i++) {
