#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define ALPHABET_SIZE 256

typedef struct SuffixTreeNode {
    struct SuffixTreeNode *children[ALPHABET_SIZE];
    struct SuffixTreeNode *suffixLink;
    int start;
    int *end;
    int suffixIndex;
} SuffixTreeNode;

typedef struct SuffixTree {
    char *text;
    SuffixTreeNode *root;
    SuffixTreeNode *lastNewNode;
    SuffixTreeNode *activeNode;
    int activeEdge;
    int activeLength;
    int remainingSuffixCount;
    int leafEnd;
    int size;
    int *rootEnd;
    int *splitEnd;
} SuffixTree;

SuffixTreeNode *newNode(int start, int *end, SuffixTree *tree) {
    SuffixTreeNode *node = malloc(sizeof(SuffixTreeNode));
    for (int i = 0; i < ALPHABET_SIZE; i++)
        node->children[i] = NULL;
    node->suffixLink = tree->root;
    node->start = start;
    node->end = end;
    node->suffixIndex = -1;
    return node;
}

int edgeLength(SuffixTreeNode *node) {
    return node == NULL ? 0 : *(node->end) - (node->start) + 1;
}

int walkDown(SuffixTreeNode *currNode, SuffixTree *tree) {
    if (tree->activeLength >= edgeLength(currNode)) {
        tree->activeEdge += edgeLength(currNode);
        tree->activeLength -= edgeLength(currNode);
        tree->activeNode = currNode;
        return 1;
    }
    return 0;
}

void extendSuffixTree(SuffixTree *tree, int pos) {
    tree->leafEnd = pos;
    tree->remainingSuffixCount++;
    tree->lastNewNode = NULL;
    while (tree->remainingSuffixCount > 0) {
        if (tree->activeLength == 0) tree->activeEdge = pos;

        char currentChar = tree->text[tree->activeEdge];
        if (tree->activeNode->children[currentChar] == NULL) {
            tree->activeNode->children[currentChar] = newNode(pos, &tree->leafEnd, tree);
            if (tree->lastNewNode != NULL) {
                tree->lastNewNode->suffixLink = tree->activeNode;
                tree->lastNewNode = NULL;
            }
        } else {
            SuffixTreeNode *next = tree->activeNode->children[currentChar];
            if (walkDown(next, tree)) continue;
            if (tree->text[next->start + tree->activeLength] == tree->text[pos]) {
                if (tree->lastNewNode != NULL && tree->activeNode != tree->root) {
                    tree->lastNewNode->suffixLink = tree->activeNode;
                    tree->lastNewNode = NULL;
                }
                tree->activeLength++;
                break;
            }

            tree->splitEnd = malloc(sizeof(int));
            *(tree->splitEnd) = next->start + tree->activeLength - 1;

            SuffixTreeNode *split = newNode(next->start, tree->splitEnd, tree);
            tree->activeNode->children[currentChar] = split;

            split->children[tree->text[pos]] = newNode(pos, &tree->leafEnd, tree);
            next->start += tree->activeLength;
            split->children[currentChar] = next;

            if (tree->lastNewNode != NULL)
                tree->lastNewNode->suffixLink = split;

            tree->lastNewNode = split;
        }

        tree->remainingSuffixCount--;
        if (tree->activeNode == tree->root && tree->activeLength > 0) {
            tree->activeLength--;
            tree->activeEdge = pos - tree->remainingSuffixCount + 1;
        } else if (tree->activeNode != tree->root)
            tree->activeNode = tree->activeNode->suffixLink;
    }
}

void setSuffixIndex(SuffixTreeNode *node, int labelHeight, SuffixTree *tree) {
    if (node == NULL) return;
    int leaf = 1;
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        if (node->children[i] != NULL) {
            leaf = 0;
            setSuffixIndex(node->children[i], labelHeight + edgeLength(node->children[i]), tree);
        }
    }
    if (leaf) {
        node->suffixIndex = tree->size - labelHeight;
        printf("Suffix Leaf found at Index: %d\n", node->suffixIndex);
    }
}

void buildSuffixTree(SuffixTree *tree) {
    tree->size = strlen(tree->text);
    int *rootEnd = malloc(sizeof(int));
    *rootEnd = -1;
    tree->root = newNode(-1, rootEnd, tree);
    tree->activeNode = tree->root;
    for (int i = 0; i < tree->size; i++) extendSuffixTree(tree, i);
    int labelHeight = 0;
    setSuffixIndex(tree->root, labelHeight, tree);
}

void freeSuffixTree(SuffixTreeNode *node) {
    if (node == NULL) return;
    for (int i = 0; i < ALPHABET_SIZE; i++)
        if (node->children[i] != NULL) freeSuffixTree(node->children[i]);
    if (node->suffixIndex == -1)
        free(node->end);
    free(node);
}

int traverseEdge(char *str, int idx, int start, int end, char *text) {
    for (int k = start; k <= end && str[idx] != '\0'; k++, idx++)
        if (text[k] != str[idx])
            return -1;
    if (str[idx] == '\0')
        return 1;
    return 0;
}

int doTraversalToCountLeaf(SuffixTreeNode *node, char *str, int idx, char *text) {
    if (node == NULL) return -1;
    int res = -1;
    if (node->start != -1)
        res = traverseEdge(str, idx, node->start, *(node->end), text);
    if (res == -1) return -1;
    if (res == 1) {
        if (node->suffixIndex > -1) printf("Found at Index %d\n", node->suffixIndex);
        return 1;
    }
    idx += edgeLength(node);
    if (node->children[str[idx]] != NULL)
        return doTraversalToCountLeaf(node->children[str[idx]], str, idx, text);
    return -1;
}

void searchString(SuffixTree *tree, char* str) {
    if (doTraversalToCountLeaf(tree->root, str, 0, tree->text) == -1)
        printf("Pattern not found.\n");
}

int main() {
    char text[100], substr[100];
    printf("Enter Text: ");
    scanf("%s", text);
    SuffixTree tree;
    tree.text = text;
    buildSuffixTree(&tree);

    while (1) {
        printf("Enter Substring to Search (or type EXIT to quit): ");
        scanf("%s", substr);
        if (strcmp(substr, "EXIT") == 0) break;
        searchString(&tree, substr);
    }

    freeSuffixTree(tree.root);
    return 0;
}

function bubbleSortGrades(grades) {
    let sortedGrades = grades.slice();
    let swapCount = 0;
    let n = sortedGrades.length;

    for (let i = 0; i < n - 1; i++) {
        for (let j = 0; j < n - i - 1; j++) {
            if (sortedGrades[j] > sortedGrades[j + 1]) {
                [sortedGrades[j], sortedGrades[j + 1]] = [sortedGrades[j + 1], sortedGrades[j]];
                swapCount++;
            }
        }
    }

    return {
        sortedGrades: sortedGrades,
        swapCount: swapCount
    };
}

#include <iostream>
#include <vector>
#include <queue>
#include <unordered_map>

using namespace std;

struct Node {
    char ch;
    int freq;
    Node* left;
    Node* right;
    Node(char c, int f) : ch(c), freq(f), left(nullptr), right(nullptr) {}
};

struct Compare {
    bool operator()(Node* l, Node* r) {
        return l->freq > r->freq;
    }
};

void buildMap(Node* root, unordered_map<char, string>& huffmanCode, string str) {
    if (!root) return;
    if (!root->left && !root->right) huffmanCode[root->ch] = str;
    buildMap(root->left, huffmanCode, str + "0");
    buildMap(root->right, huffmanCode, str + "1");
}

void encode(string text) {
    unordered_map<char, int> freq;
    for (char ch : text) {
        freq[ch]++;
    }

    priority_queue<Node*, vector<Node*>, Compare> pq;

    for (auto pair : freq) {
        pq.push(new Node(pair.first, pair.second));
    }

    while (pq.size() != 1) {
        Node* left = pq.top(); pq.pop();
        Node* right = pq.top(); pq.pop();
        Node* sum = new Node('\0', left->freq + right->freq);
        sum->left = left;
        sum->right = right;
        pq.push(sum);
    }

    Node* root = pq.top();

    unordered_map<char, string> huffmanCode;
    buildMap(root, huffmanCode, "");

    cout << "Huffman Codes:\n";
    for (auto pair : huffmanCode) {
        cout << pair.first << ": " << pair.second << '\n';
    }

    cout << "\nEncoded String:\n";
    string encodedString = "";
    for (char ch : text) {
        encodedString += huffmanCode[ch];
    }
    cout << encodedString << '\n';
}

int main() {
    string text;
    cout << "Enter text to encode: ";
    getline(cin, text);
    encode(text);
    return 0;
}

fn is_safe(board: &Vec<Vec<i32>>, row: usize, col: usize) -> bool {
    for i in 0..col {
        if board[row][i] == 1 {
            return false;
        }
    }

    for (i, j) in (0..row).rev().zip((0..col).rev()) {
        if board[i][j] == 1 {
            return false;
        }
    }

    for (i, j) in (row+1..8).zip((0..col).rev()) {
        if board[i][j] == 1 {
            return false;
        }
    }

    true
}

fn solve(board: &mut Vec<Vec<i32>>, col: usize, results: &mut Vec<Vec<String>>) {
    if col >= 8 {
        let mut solution = vec![];
        for i in 0..8 {
            let mut s = String::new();
            for j in 0..8 {
                if board[i][j] == 1 {
                    s.push('Q');
                } else {
                    s.push('.');
                }
            }
            solution.push(s);
        }
        results.push(solution);
        return;
    }

    for i in 0..8 {
        if is_safe(board, i, col) {
            board[i][col] = 1;
            solve(board, col + 1, results);
            board[i][col] = 0;
        }
    }
}

fn main() {
    let mut board = vec![vec![0; 8]; 8];
    let mut results = vec![];
    solve(&mut board, 0, &mut results);

    for solution in results {
        for row in solution {
            println!("{}", row);
        }
        println!();
    }

    println!("Total solutions: {}", results.len());
}

