    int duration;
    int priority;
};

// Function to find the maximum priority within 8 hour limit
int maxPrioritySchedule(const vector<Task>& tasks, int timeLimit) {
    int n = tasks.size();
    vector<vector<int>> dp(n + 1, vector<int>(timeLimit + 1, 0));

    for (int i = 1; i <= n; ++i) {
        for (int t = 1; t <= timeLimit; ++t) {
            if (tasks[i - 1].duration <= t) {
                dp[i][t] = max(dp[i - 1][t],
                               dp[i - 1][t - tasks[i - 1].duration] + tasks[i - 1].priority);
            } else {
                dp[i][t] = dp[i - 1][t];
            }
        }
    }
    return dp[n][timeLimit];
}

