fn prims_algorithm(n: usize, edges: &[(usize, usize, i32)]) -> Vec<(usize, usize, i32)> {
    let mut graph = vec![Vec::new(); n];
    for &(u, v, w) in edges {
        graph[u].push(Edge { weight: w, node: v });
        graph[v].push(Edge { weight: w, node: u });
    }

    let mut mst_edges = Vec::new();
    let mut visited = HashSet::new();
    let mut heap = BinaryHeap::new();

    visited.insert(0);
    for &e in &graph[0] {
        heap.push(e);
    }

    while let Some(Edge { weight, node }) = heap.pop() {
        if !visited.insert(node) {
            continue;
        }
        mst_edges.push((0, node, weight)); // Initial assumption, will adjust source node later.

        for &edge in &graph[node] {
            if !visited.contains(&edge.node) {
                heap.push(edge);
            }
        }
    }

    mst_edges
}

