class BloomFilter {
    constructor(size, hashCount) {
        this.size = size;
        this.hashCount = hashCount;
        this.bitArray = new Array(size).fill(0);
    }

    hash1(item) {
        let hash = 0;
        for (let i = 0; i < item.length; i++) {
            hash = (hash << 5) - hash + item.charCodeAt(i);
            hash = hash & hash;
        }
        return Math.abs(hash % this.size);
    }

    hash2(item) {
        let hash = 0;
        for (let i = 0; i < item.length; i++) {
            hash = item.charCodeAt(i) + (hash << 6) + (hash << 16) - hash;
        }
        return Math.abs(hash % this.size);
    }

    add(item) {
        for (let i = 0; i < this.hashCount; i++) {
            const combinedHash = (this.hash1(item) + i * this.hash2(item)) % this.size;
            this.bitArray[combinedHash] = 1;
        }
        this.displayFilterState('After Adding');
    }

    contains(item) {
        for (let i = 0; i < this.hashCount; i++) {
            const combinedHash = (this.hash1(item) + i * this.hash2(item)) % this.size;
            if (this.bitArray[combinedHash] === 0) {
                return false;
            }
        }
        return true;
    }

    displayFilterState(state) {
        console.log(`${state} Filter State: `, this.bitArray.join(''));
    }
}

