struct DisjointSet {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DisjointSet {
    fn new(n: usize) -> Self {
        let mut parent = Vec::with_capacity(n);
        let mut rank = vec![0; n];
        for i in 0..n {
            parent.push(i);
        }
        DisjointSet { parent, rank }
    }

    fn find(&mut self, u: usize) -> usize {
        if self.parent[u] != u {
            self.parent[u] = self.find(self.parent[u]); // Path compression
        }
        self.parent[u]
    }

    fn union(&mut self, u: usize, v: usize) {
        let root_u = self.find(u);
        let root_v = self.find(v);

        if root_u != root_v {
            if self.rank[root_u] > self.rank[root_v] {
                self.parent[root_v] = root_u;
            } else if self.rank[root_u] < self.rank[root_v] {
                self.parent[root_u] = root_v;
            } else {
                self.parent[root_v] = root_u;
                self.rank[root_u] += 1;
            }
        }
    }
}

fn kruskal_mst(vertices: usize, edges: &mut Vec<Edge>) -> Vec<Edge> {
    edges.sort();
    let mut disjoint_set = DisjointSet::new(vertices);
    let mut mst = Vec::new();

    for edge in edges.iter() {
        if disjoint_set.find(edge.u) != disjoint_set.find(edge.v) {
            disjoint_set.union(edge.u, edge.v);
            mst.push(edge.clone());
        }
    }

    mst
}

