class BinaryLiftingLCA {
    constructor(root) {
        this.LOG = 20;  // Assuming max 2^20 nodes in tree
        this.root = root;
        this.depth = {};
        this.up = {};
    }

    preprocess() {
        const dfs = (node, parent) => {
            if (!node) return;
            this.up[node.val] = new Array(this.LOG).fill(null);
            this.up[node.val][0] = parent ? parent.val : null;
            for (let i = 1; i < this.LOG; i++) {
                if (this.up[node.val][i - 1] !== null) {
                    this.up[node.val][i] = this.up[this.up[node.val][i - 1]][i - 1];
                }
            }
            this.depth[node.val] = parent ? this.depth[parent.val] + 1 : 0;
            dfs(node.left, node);
            dfs(node.right, node);
        };
        dfs(this.root, null);
    }

    getLCA(u, v) {
        if (!(u in this.depth) || !(v in this.depth)) return null;

        if (this.depth[u] < this.depth[v]) [u, v] = [v, u];

        let diff = this.depth[u] - this.depth[v];

        for (let i = 0; i < this.LOG; i++) {
            if ((diff & (1 << i)) !== 0) {
                u = this.up[u][i];
            }
        }

        if (u === v) return u;

        for (let i = this.LOG - 1; i >= 0; i--) {
            if (this.up[u][i] !== this.up[v][i]) {
                u = this.up[u][i];
                v = this.up[v][i];
            }
        }

        return this.up[u][0];
    }
}

