bool isOperator(const std::string& token) {
    return token == "+" || token == "-" || token == "*" || token == "/";
}

bool isValidPostfix(const std::string& expression) {
    int counter = 0;
    std::istringstream iss(expression);
    std::string token;
    while (iss >> token) {
        if (isdigit(token[0]) || (token[0] == '-' && isdigit(token[1])))
            counter++;
        else if (isOperator(token))
            counter -= 1;
        if (counter < 1) return false;
    }
    return counter == 1;
}

double evaluatePostfix(const std::string& expression) {
    std::stack<double> stack;
    std::istringstream iss(expression);
    std::string token;
    while (iss >> token) {
        if (isdigit(token[0]) || (token[0] == '-' && isdigit(token[1]))) {
            stack.push(std::stod(token));
        } else if (isOperator(token)) {
            double b = stack.top(); stack.pop();
            double a = stack.top(); stack.pop();
            if (token == "+") stack.push(a + b);
            else if (token == "-") stack.push(a - b);
            else if (token == "*") stack.push(a * b);
            else if (token == "/") stack.push(a / b);
        }
    }
    return stack.top();
}

int main() {
    std::string input;
    std::cout << "Enter a postfix expression: ";
    std::getline(std::cin, input);

    if (!isValidPostfix(input)) {
        std::cerr << "Invalid postfix notation." << std::endl;
        return 1;
    }

    double result = evaluatePostfix(input);
    std::cout << "Result: " << result << std::endl;
    return 0;
}

import java.util.PriorityQueue;

public class RunningMedian {
    private PriorityQueue<Integer> lowerHalf; // Max-heap for the lower half of numbers
    private PriorityQueue<Integer> upperHalf; // Min-heap for the upper half of numbers

    public RunningMedian() {
        lowerHalf = new PriorityQueue<>((a, b) -> b - a);
        upperHalf = new PriorityQueue<>();
    }

    public void addNumber(int num) {
        if (lowerHalf.isEmpty() || num <= lowerHalf.peek()) {
            lowerHalf.offer(num);
        } else {
            upperHalf.offer(num);
        }

        // Balance the heaps if their sizes differ by more than one
        if (lowerHalf.size() > upperHalf.size() + 1) {
            upperHalf.offer(lowerHalf.poll());
        } else if (upperHalf.size() > lowerHalf.size()) {
            lowerHalf.offer(upperHalf.poll());
        }
    }

    public void removeNumber(int num) {
        if (!lowerHalf.remove(num)) {
            upperHalf.remove(num);
        }

        // Balance the heaps if their sizes differ by more than one
        if (lowerHalf.size() > upperHalf.size() + 1) {
            upperHalf.offer(lowerHalf.poll());
        } else if (upperHalf.size() > lowerHalf.size()) {
            lowerHalf.offer(upperHalf.poll());
        }
    }

    public double getMedian() {
        if (lowerHalf.size() == upperHalf.size()) {
            return (lowerHalf.peek() + upperHalf.peek()) / 2.0;
        } else {
            return lowerHalf.peek();
        }
    }

    public static void main(String[] args) {
        RunningMedian rm = new RunningMedian();
        rm.addNumber(1);
        rm.addNumber(2);
        System.out.println(rm.getMedian()); // Output: 1.5
        rm.addNumber(3);
        System.out.println(rm.getMedian()); // Output: 2
        rm.removeNumber(2);
        System.out.println(rm.getMedian()); // Output: 1.5
    }
}

