class FibonacciHeap:
    def __init__(self):
        self.min = None
        self.roots = 0
        self.total_nodes = 0

    def _merge_roots(self, h):
        if h is None:
            return
        if self.min is None:
            self.min = h
        else:
            self._concatenate_lists(self.min, h)
            if h.key < self.min.key:
                self.min = h

    def _concatenate_lists(self, a, b):
        temp = a.right
        a.right = b.right
        b.right.left = a
        b.right = temp
        temp.left = b

    def insert(self, key):
        node = Node(key)
        self._merge_roots(node)
        self.roots += 1
        self.total_nodes += 1

    def extract_min(self):
        z = self.min
        if z is not None:
            if z.child is not None:
                children = []
                child = z.child
                while True:
                    children.append(child)
                    child = child.right
                    if child == z.child:
                        break
                for c in children:
                    self._merge_roots(c)
                    c.parent = None
            self._remove_node(z)
            if z == z.right:
                self.min = None
            else:
                self.min = z.right
                self._consolidate()
            self.total_nodes -= 1
        return z.key if z else None

    def _remove_node(self, node):
        node.left.right = node.right
        node.right.left = node.left

    def _consolidate(self):
        A = [None] * (self.total_nodes + 1)
        nodes = [x for x in self._iterate_nodes(self.min)]
        for w in nodes:
            x = w
            d = x.degree
            while A[d] is not None:
                y = A[d]
                if x.key > y.key:
                    x, y = y, x
                self._link(y, x)
                A[d] = None
                d += 1
            A[d] = x
        self.min = None
        for i in range(len(A)):
            if A[i] is not None:
                if self.min is None or A[i].key < self.min.key:
                    self.min = A[i]

    def _link(self, y, x):
        self._remove_node(y)
        y.left = y.right = y
        if x.child is None:
            x.child = y
        else:
            self._concatenate_lists(x.child, y)
        y.parent = x
        x.degree += 1
        y.mark = False

    def merge(self, other_heap):
        if not isinstance(other_heap, FibonacciHeap):
            raise TypeError("Can only merge with another FibonacciHeap")
        self._merge_roots(other_heap.min)
        self.total_nodes += other_heap.total_nodes
        self.roots += other_heap.roots
        other_heap.min = None
        other_heap.total_nodes = 0
        other_heap.roots = 0

    def _iterate_nodes(self, start):
        current = stop = start
        flag = False
        while True:
            if current == stop and flag:
                break
            elif current == stop:
                flag = True
            yield current
            current = current.right

