struct Graph {
    edges: Vec<Edge>,
    num_vertices: usize,
}

impl Graph {
    fn new(num_vertices: usize) -> Self {
        Graph {
            edges: Vec::new(),
            num_vertices,
        }
    }

    fn add_edge(&mut self, from: usize, to: usize, weight: i32) {
        self.edges.push(Edge::new(from, to, weight));
    }

    fn bellman_ford(&self, source: usize) -> Result<Vec<i32>, &str> {
        let mut distances = vec![i32::MAX; self.num_vertices];
        distances[source] = 0;

        for _ in 0..self.num_vertices - 1 {
            for edge in &self.edges {
                if distances[edge.from] != i32::MAX {
                    let new_distance = distances[edge.from] + edge.weight;
                    if new_distance < distances[edge.to] {
                        distances[edge.to] = new_distance;
                    }
                }
            }
        }

        for edge in &self.edges {
            if distances[edge.from] != i32::MAX {
                if distances[edge.from] + edge.weight < distances[edge.to] {
                    return Err("Graph contains a negative weight cycle");
                }
            }
        }

        Ok(distances)
    }
}

