        let timeLeft = maxDurationPerDay;
        const dailyPlan = [];

        for (const exercise of exercises) {
            if (exercise.duration <= timeLeft) {
                dailyPlan.push(exercise);
                timeLeft -= exercise.duration;
            }
        }
        weeklyPlan.push(dailyPlan);
    }

    return weeklyPlan;
}

const exercises = [
    { name: 'Running', duration: 30, calories: 300 },
    { name: 'Cycling', duration: 30, calories: 250 },
    { name: 'Swimming', duration: 30, calories: 400 },
    { name: 'Yoga', duration: 60, calories: 200 },
    { name: 'Walking', duration: 30, calories: 150 }
];

const maxDurationPerDay = 60; // 1 hour in minutes
